WITH RECURSIVE cte AS (
    select 0 as n, b.* from u_member b where b.id = #{id}
    union all
    select n+1, a.* from u_member a inner join cte c on a.ID = c.pid
)select * from cte where deleted = 0

WITH RECURSIVE cte AS (
    select 0 as n, b.* from u_member b where b.id = #{id}
    union all
    select n+1, a.* from u_member a inner join cte c on a.pid = c.id
) select * from cte where deleted = 0

mapper.update:
update u_member

        invite_level_id = invite_level_id + #{change},


        and id = #{uid}
        and invite_level_id <= #{max}

update u_member


        prize_amount = prize_amount + #{prizeAmount},


        prize_bonus_day = #{prizeBonusDay},



    id = #{id}

        and prize_bonus_day < #{prizeBonusDay}

UPDATE u_member AS ff


        ff.frozen_performance = IF(valid != 1, ff.frozen_performance + #{frozenPerformance}, ff.frozen_performance),


        ff.team_performance = IF(valid = 1,ff.team_performance + #{teamPerformance}, ff.team_performance),


        ff.performance_update_at = #{performanceUpdateAt},


WHERE EXISTS(
WITH RECURSIVE CTE AS (
select b.id,b.pid from u_member b where b.deleted = 0 and b.id = #{id}
union all
select a.id,a.pid from u_member a inner join cte c on a.ID = c.pid where a.deleted = 0
)
select 1 from CTE ct where ct.id = ff.id and ct.id  <> #{id}
)

update u_member


        valid = #{valid},


        valid_at = #{validAt},


        invite_code = #{inviteCode},



    id = #{id}
    and valid <> #{valid}

mapper.select:
SELECT pid AS uid, COALESCE(SUM(CASE WHEN rn > 1 THEN total_performance ELSE 0 END), 0) AS `smallPerformance` FROM ( SELECT pid, (performance + team_performance) AS total_performance, ROW_NUMBER() OVER ( PARTITION BY pid ORDER BY (performance + team_performance) DESC ) AS rn FROM u_member WHERE pid in
#{item}
) ranked_data GROUP BY pid
